DECLARE @TemplateID_f8b04445 UNIQUEIDENTIFIER,
@TypeID_f8b04445 UNIQUEIDENTIFIER,
@TemplateText_f8b04445 NVARCHAR(MAX),
@Priority_f8b04445 INT,
