DECLARE @ID_8e844f37 UNIQUEIDENTIFIER,
@Name_8e844f37 NVARCHAR(255),
@CategoryID_8e844f37 UNIQUEIDENTIFIER,
@UserQuestion_8e844f37 NVARCHAR(MAX),
@Description_8e844f37 NVARCHAR(MAX),
@SQL_8e844f37 NVARCHAR(MAX),
@TechnicalDescription_8e844f37 NVARCHAR(MAX),
@OriginalSQL_8e844f37 NVARCHAR(MAX),
@Feedback_8e844f37 NVARCHAR(MAX),
@Status_8e844f37 NVARCHAR(15),
@QualityRank_8e844f37 INT,
@ExecutionCostRank_8e844f37 INT,
@UsesTemplate_8e844f37 BIT,
@AuditQueryRuns_8e844f37 BIT,
@CacheEnabled_8e844f37 BIT,
@CacheTTLMinutes_8e844f37 INT,
@CacheMaxSize_8e844f37 INT,
@EmbeddingVector_8e844f37 NVARCHAR(MAX),
@EmbeddingModelID_8e844f37 UNIQUEIDENTIFIER,
@CacheValidationSQL_8e844f37 NVARCHAR(MAX),
@SQLDialectID_8e844f37 UNIQUEIDENTIFIER,
@Reusable_8e844f37 BIT
SET
  @ID_8e844f37 = '34D2D4D2-C727-4366-996F-3AAF87FC103E'
SET
  @Name_8e844f37 = N'GetArtifactVersionsByID'
SET
  @CategoryID_8e844f37 = '5609FBC7-381C-4F9C-9C74-04B52C1FF3DA'
SET
  @UserQuestion_8e844f37 = N'What are the full artifact version records for a given set of artifact version IDs?'
SET
  @Description_8e844f37 = N'Returns artifact version fields (name, content mode, file ref, content, mime) joined with the parent artifact and artifact type (including ToolLibraryClass) for a supplied list of ArtifactVersionIDs.'
SET
  @SQL_8e844f37 = N'-- Get Artifact Versions By ID - Single optimized query
-- Returns all fields needed to construct InputArtifact records for agent context gathering.
-- Replaces a per-version loop that did two Load() calls (ArtifactVersion + Artifact) per row.
--
-- Parameters:
--   @versionIds: Array of ArtifactVersionIDs (rendered via sqlIn filter)

SELECT
    av.ID as VersionID,
    av.Name as VersionName,
    av.ContentMode,
    av.FileID,
    av.Content,
    av.MimeType,

    a.Name as ArtifactName,
    a.Type as TypeName,

    at.ToolLibraryClass

FROM [${flyway:defaultSchema}].[vwArtifactVersions] av
INNER JOIN [${flyway:defaultSchema}].[vwArtifacts] a ON av.ArtifactID = a.ID
INNER JOIN [${flyway:defaultSchema}].[vwArtifactTypes] at ON a.TypeID = at.ID

WHERE av.ID IN {{ versionIds | sqlIn }}
'
SET
  @TechnicalDescription_8e844f37 = N'Single-query replacement for AgentRunner.gatherConversationArtifacts per-junction loop that issued two Load() calls per row (MJ: Artifact Versions + MJ: Artifacts). Joins vwArtifactVersions → vwArtifacts → vwArtifactTypes so ToolLibraryClass is available without a third lookup. Accepts a JS array via {{ versionIds | sqlIn }}.'
SET
  @Status_8e844f37 = N'Approved'
SET
  @QualityRank_8e844f37 = 9
SET
  @ExecutionCostRank_8e844f37 = 2
SET
  @UsesTemplate_8e844f37 = 1
SET
  @AuditQueryRuns_8e844f37 = 0
SET
